const trigger = $('Workflow Trigger').first().json;
const docs = $input.all().map((entry) => entry.json).filter((entry) => entry && entry.document);

if (!trigger.webhook_url) {
  return [{ json: { success: false, message: 'Webhook de vendas não configurado.' } }];
}

if (docs.length === 0) {
  return [{ json: { success: false, empty: true, message: 'Carrinho vazio.' } }];
}

const parsedDocs = docs.map((raw) => {
  const fields = raw.document.fields || {};
  const rawItems = fields.items?.arrayValue?.values || [];
  const items = rawItems
    .map((entry) => {
      const itemFields = entry.mapValue?.fields || {};
      const quantity = Number(itemFields.quantity?.integerValue ?? itemFields.quantity?.doubleValue ?? 1);
      const price = Number(itemFields.price?.doubleValue ?? itemFields.price?.integerValue ?? 0);
      return {
        sku: itemFields.sku?.stringValue || '',
        product_name: itemFields.product_name?.stringValue || '',
        quantity,
        unit_price: price,
        subtotal: Math.round(quantity * price * 100) / 100,
      };
    })
    .filter((item) => item.sku && item.product_name && item.quantity > 0);

  return {
    id: raw.document.name.split('/').pop(),
    updatedAt: fields.updated_at?.stringValue || fields.created_at?.stringValue || '',
    items,
  };
}).sort((a, b) => String(b.updatedAt).localeCompare(String(a.updatedAt)));

const mergedBySku = new Map();
for (const doc of parsedDocs) {
  for (const item of doc.items) {
    const sku = String(item.sku || '').trim();
    if (!sku) {
      continue;
    }

    const current = mergedBySku.get(sku);
    if (current) {
      current.quantity += Number(item.quantity || 0);
      current.subtotal = Math.round(current.quantity * current.unit_price * 100) / 100;
      if (!current.product_name && item.product_name) {
        current.product_name = item.product_name;
      }
      if (!current.unit_price && item.unit_price) {
        current.unit_price = item.unit_price;
        current.subtotal = Math.round(current.quantity * current.unit_price * 100) / 100;
      }
    } else {
      mergedBySku.set(sku, {
        sku,
        product_name: item.product_name,
        quantity: Number(item.quantity || 0),
        unit_price: Number(item.unit_price || 0),
        subtotal: Math.round(Number(item.quantity || 0) * Number(item.unit_price || 0) * 100) / 100,
      });
    }
  }
}

const items = Array.from(mergedBySku.values()).filter((item) => item.sku && item.product_name && item.quantity > 0);
if (items.length === 0) {
  return [{ json: { success: false, empty: true, message: 'Carrinho vazio.' } }];
}

const total = Math.round(items.reduce((sum, item) => sum + Number(item.subtotal || 0), 0) * 100) / 100;
const cartId = parsedDocs[0]?.id || '';
const status = String(trigger.status || 'pending').trim() || 'pending';
const sale = {
  external_id: cartId || '',
  customer_id: trigger.customer_id || '',
  customer_name: trigger.customer_name || '',
  customer_whatsapp: trigger.phone || '',
  customer_email: trigger.customer_email || '',
  customer_address: trigger.customer_address || '',
  items,
  total,
  status,
  source: 'whatsapp_automation',
  notes: trigger.notes || '',
  conversation_id: trigger.conversation_id || '',
  decrement_stock: ['true', '1', 'yes'].includes(String(trigger.decrement_stock || '').toLowerCase()),
};

return [{
  json: {
    _webhookUrl: trigger.webhook_url,
    _cartId: cartId,
    _tenantId: trigger.tenant_id,
    sale,
  }
}];

const response = $input.first().json || {};
const salePayload = $('Montar Payload da Venda').first().json;

return [{
  json: {
    success: response.ok === true,
    ok: response.ok === true,
    sale_id: response.saleId || null,
    customer_id: response.customerId || salePayload.sale?.customer_id || null,
    created: response.created === true,
    total: salePayload.sale?.total || 0,
    item_count: salePayload.sale?.items?.length || 0,
    message: response.ok === true
      ? 'Venda registrada com sucesso.'
      : (response.message || response.error || 'Nao foi possivel registrar a venda.'),
  }
}];
